let rfbModal=null;function openVncModal(){document.getElementById("vncModal").classList.add("active")}function closeVncModal(){rfbModal&&(rfbModal.disconnect(),rfbModal=null),document.getElementById("vncModal").classList.remove("active"),document.getElementById("vnc-modal-details").classList.add("hidden"),document.getElementById("vnc-modal-placeholder").style.display="flex"}async function connectVncModal(){const e=document.getElementById("btn-vnc-modal-connect"),t=e.innerHTML;e.disabled=!0,e.innerHTML='<i class="fas fa-spinner fa-spin"></i> Conectando...';try{const e=await fetch(`/api/servers/vnc?id=${serverId}`),t=await e.json();if(!t.success)return document.getElementById("vnc-modal-error").textContent=t.message||"Error al obtener credenciales VNC",void document.getElementById("vnc-modal-error").classList.remove("hidden");const n=t.vnc_url,d=t.vnc_password;if(!n||!d)return document.getElementById("vnc-modal-error").textContent=LANG_MAN.vnc_err_incomplete,void document.getElementById("vnc-modal-error").classList.remove("hidden");document.getElementById("vnc-modal-password").textContent=d,setupCopy("copy-vnc-modal-pass",d),document.getElementById("vnc-modal-placeholder").style.display="none",document.getElementById("vnc-modal-details").classList.remove("hidden"),document.getElementById("vnc-modal-status-text").classList.remove("hidden"),document.getElementById("vnc-modal-status-text").textContent="Conectando...";let o=n;!n||n.startsWith("ws")||n.startsWith("http")||(o="wss://hypervisor.kordindustries.io:443/vnc?url="+encodeURIComponent(n));const l=document.getElementById("vnc-modal-screen");rfbModal=new RFB(l,o,{credentials:{password:d,username:"root"}}),rfbModal.addEventListener("connect",(()=>{document.getElementById("vnc-modal-status-text").classList.add("hidden"),document.getElementById("vnc-modal-error").classList.add("hidden")})),rfbModal.addEventListener("disconnect",(e=>{const t=e.detail.clean?"Conexión cerrada":"Conexión perdida";document.getElementById("vnc-modal-status-text").textContent=t,document.getElementById("vnc-modal-status-text").classList.remove("hidden")})),rfbModal.addEventListener("credentialsfailed",(e=>{document.getElementById("vnc-modal-error").textContent="Error de autenticación VNC. Verifica la contraseña.",document.getElementById("vnc-modal-error").classList.remove("hidden"),document.getElementById("vnc-modal-status-text").classList.add("hidden")})),rfbModal.addEventListener("securityfailure",(e=>{document.getElementById("vnc-modal-error").textContent="Error de seguridad VNC: "+e.detail.reason,document.getElementById("vnc-modal-error").classList.remove("hidden"),document.getElementById("vnc-modal-status-text").classList.add("hidden")})),rfbModal.scaleViewport=!0,rfbModal.resizeSession=!0}catch(e){console.error("VNC Error:",e),document.getElementById("vnc-modal-error").textContent=LANG_MAN.vnc_err_connection+e.message,document.getElementById("vnc-modal-error").classList.remove("hidden")}finally{e.innerHTML=t,e.disabled=!1}}function disconnectVncModal(){rfbModal&&(rfbModal.disconnect(),rfbModal=null),document.getElementById("vnc-modal-details").classList.add("hidden"),document.getElementById("vnc-modal-placeholder").style.display="flex",document.getElementById("vnc-modal-status-text").textContent="Ready",document.getElementById("vnc-modal-status-text").classList.remove("hidden")}function sendCtrlAltDelModal(){rfbModal&&rfbModal.sendCtrlAltDel()}function toggleVncModalKeyboard(){if(rfbModal){rfbModal.showKeyboard=!rfbModal.showKeyboard;const e=document.getElementById("btn-vnc-modal-keyboard");rfbModal.showKeyboard?(e.style.color="var(--primary)",e.title="Hide Virtual Keyboard"):(e.style.color="",e.title="Virtual Keyboard")}}